parameters.text:
You are an antenna design expert. Generate candidate parameter sets for optimization.

Antenna type: {{ $json.antenna_type }}
Target frequency: {{ $json.target_frequency }} Hz
Target S11: {{ $json.target_s11 }} dB
Target bandwidth: {{ $json.target_bandwidth_pct }}%
Constraints: {{ JSON.stringify($json.constraints) }}

Iteration: {{ $json.iteration }} / {{ $json.max_iterations }}

{% if $json.iteration > 0 %}
Previous results:
{{ JSON.stringify($json.history, null, 2) }}

Best design so far:
{{ JSON.stringify($json.best_design, null, 2) }}
Best score: {{ $json.best_score }}

Based on previous results, suggest 5 REFINED parameter sets that should improve performance.
Focus on the parameters that had the most impact. Use interpolation/extrapolation from best results.
{% else %}
Generate 5 diverse initial candidate parameter sets covering the design space.
Include conservative, aggressive, and balanced designs.
{% endif %}

Return ONLY a JSON array of 5 objects. Each object must have these fields:
- candidate_id: number (1-5)
- description: string (brief design rationale)
- parameters: object (antenna-specific parameters in SI units)

Example for half_wave_dipole:
[{"candidate_id":1,"description":"Standard half-wave at target freq","parameters":{"length_m":0.0625,"wire_radius_m":0.001}}]

Return valid JSON array only, no markdown.

parameters.jsCode:
const state = $('Init Optimization State').item.json.iteration === undefined
  ? $('Init Optimization State').item.json
  : ($('Loop Check').item?.json || $('Init Optimization State').item.json);

const aiOutput = $('Claude Generate Candidates').item.json.output || '';

// Parse JSON array from AI output
let candidates = [];
try {
  // Try direct parse first
  candidates = JSON.parse(aiOutput);
} catch {
  // Try to extract JSON array from text
  const match = aiOutput.match(/\[\s*\{[\s\S]*\}\s*\]/);
  if (match) {
    candidates = JSON.parse(match[0]);
  }
}

if (!Array.isArray(candidates) || candidates.length === 0) {
  // Fallback: generate basic candidates
  const freq = state.target_frequency;
  const lambda = 3e8 / freq;
  candidates = [
    { candidate_id: 1, description: 'Half-wave baseline', parameters: { length_m: lambda / 2 } },
    { candidate_id: 2, description: 'Slightly shorter', parameters: { length_m: lambda * 0.47 } },
    { candidate_id: 3, description: 'Slightly longer', parameters: { length_m: lambda * 0.53 } },
    { candidate_id: 4, description: 'Short with thick wire', parameters: { length_m: lambda * 0.45, wire_radius_m: 0.005 } },
    { candidate_id: 5, description: 'Optimized length', parameters: { length_m: lambda * 0.48 } }
  ];
}

return candidates.map(c => ({
  json: {
    ...c,
    antenna_type: state.antenna_type,
    target_frequency: state.target_frequency,
    target_s11: state.target_s11,
    target_bandwidth_pct: state.target_bandwidth_pct,
    constraints: state.constraints,
    iteration: state.iteration,
    state_ref: state
  }
}));

const candidate = $('Simulate Each').item.json;
const response = $input.item.json;
const results = response.body || response;

return [{
  json: {
    candidate_id: candidate.candidate_id,
    description: candidate.description,
    parameters: candidate.parameters,
    results,
    state_ref: candidate.state_ref
  }
}];

const candidates = $input.all().map(i => i.json);
const state = candidates[0]?.state_ref || {};

// Score each candidate: lower = better
function scoreCandidate(c) {
  const r = c.results || {};
  const s11 = r.s11_db ?? r.s_parameters?.s11_db ?? 0;
  const z_re = r.impedance?.real ?? r.z_re ?? 50;
  const z_im = r.impedance?.imag ?? r.z_im ?? 0;
  const gain = r.gain_dbi ?? r.max_gain_dbi ?? 0;

  // S11 penalty: want below target_s11
  const s11_target = state.target_s11 || -15;
  const s11_penalty = s11 > s11_target ? (s11 - s11_target) * 5 : 0;

  // Impedance match to 50 ohm
  const z_mismatch = Math.sqrt(Math.pow(z_re - 50, 2) + Math.pow(z_im, 2)) / 50;

  // Gain bonus (negative = better score)
  const gain_bonus = -gain * 0.5;

  return s11_penalty + z_mismatch * 10 + gain_bonus;
}

const scored = candidates.map(c => ({
  ...c,
  score: scoreCandidate(c)
})).sort((a, b) => a.score - b.score);

// Update state
const newIteration = (state.iteration || 0) + 1;
const prevHistory = state.history || [];
const iterationResults = scored.map(c => ({
  candidate_id: c.candidate_id,
  description: c.description,
  parameters: c.parameters,
  score: c.score,
  s11_db: c.results?.s11_db ?? c.results?.s_parameters?.s11_db,
  z_re: c.results?.impedance?.real ?? c.results?.z_re,
  z_im: c.results?.impedance?.imag ?? c.results?.z_im,
  gain_dbi: c.results?.gain_dbi ?? c.results?.max_gain_dbi
}));

const bestThisRound = scored[0];
const prevBestScore = state.best_score ?? Infinity;
const newBest = bestThisRound.score < prevBestScore
  ? { parameters: bestThisRound.parameters, results: bestThisRound.results, score: bestThisRound.score, description: bestThisRound.description }
  : state.best_design;
const newBestScore = Math.min(bestThisRound.score, prevBestScore);

return [{
  json: {
    antenna_type: state.antenna_type,
    target_frequency: state.target_frequency,
    target_s11: state.target_s11,
    target_bandwidth_pct: state.target_bandwidth_pct,
    constraints: state.constraints,
    iteration: newIteration,
    max_iterations: state.max_iterations || 3,
    history: [...prevHistory, { iteration: newIteration, results: iterationResults }],
    best_design: newBest,
    best_score: newBestScore,
    ranked_candidates: scored
  }
}];

const state = $('Rank Candidates').item.json;
const aiReport = $('Claude Final Analysis').item.json.output || '';

return [{
  json: {
    status: 'optimization_complete',
    antenna_type: state.antenna_type,
    target_frequency: state.target_frequency,
    iterations_completed: state.iteration,
    best_design: state.best_design,
    best_score: state.best_score,
    optimization_history: state.history,
    ai_report: aiReport,
    timestamp: new Date().toISOString()
  }
}];

const error = $input.item.json;
const errorMsg = {
  status: 'error',
  error: error.execution?.error?.message || 'Unknown error',
  node: error.execution?.lastNodeExecuted || 'unknown',
  workflow: 'ae-ai-optimizer',
  timestamp: new Date().toISOString()
};
console.error('ae-ai-optimizer error:', JSON.stringify(errorMsg));
return [{ json: errorMsg }];
